class Solution {
public:
    vector<int> maximumCount(vector<int>& nums, vector<vector<int>>& queries) {
        int n = nums.size();
        vector<int> primeCount(1e5 + 1);
        for (int num : nums) {
            if (isPrime(num)) {
                primeCount[num]++;
            }
        }

        int totalPrimeCount = 0;
        for (int i = 0; i <= 1e5; i++) {
            totalPrimeCount += (primeCount[i] > 0);
        }

        vector<int> prefixPrimeCount(n + 1);
        for (int i = 0; i < n; i++) {
            prefixPrimeCount[i + 1] = prefixPrimeCount[i] + (isPrime(nums[i]));
        }

        vector<int> result;
        for (auto& query : queries) {
            int idx = query[0];
            int val = query[1];
            if (isPrime(nums[idx]) != isPrime(val)) {
                if (isPrime(nums[idx])) {
                    totalPrimeCount -= (primeCount[nums[idx]] == 1);
                    primeCount[nums[idx]]--;
                    prefixPrimeCount[idx + 1]--;
                    for (int i = idx + 2; i <= n; i++) {
                        prefixPrimeCount[i]--;
                    }
                } else {
                    primeCount[val]++;
                    totalPrimeCount += (primeCount[val] == 1);
                    prefixPrimeCount[idx + 1]++;
                    for (int i = idx + 2; i <= n; i++) {
                        prefixPrimeCount[i]++;
                    }
                }
                if (isPrime(val)) {
                    totalPrimeCount += (primeCount[val] == 1);
                    primeCount[val]++;
                } else {
                    primeCount[val]--;
                    totalPrimeCount -= (primeCount[val] == 0);
                }
            }
            nums[idx] = val;
            int maxCount = 0;
            for (int k = 1; k < n; k++) {
                maxCount = max(maxCount, prefixPrimeCount[k] + (totalPrimeCount - prefixPrimeCount[k]));
            }
            result.push_back(maxCount);
        }
        return result;
    }

    bool isPrime(int n) {
        if (n <= 1) return false;
        if (n == 2) return true;
        if (n % 2 == 0) return false;
        for (int i = 3; i * i <= n; i += 2) {
            if (n % i == 0) return false;
        }
        return true;
    }
};
